import{_ as s,c as a,o as e,aj as n}from"./chunks/framework.DZHgOU3R.js";const u=JSON.parse('{"title":"Simulation Runner","description":"","frontmatter":{},"headers":[],"relativePath":"Simulation_Runner.md","filePath":"Simulation_Runner.md"}'),t={name:"Simulation_Runner.md"};function l(o,i,r,h,d,p){return e(),a("div",null,[...i[0]||(i[0]=[n(`<h1 id="simulation-runner" tabindex="-1">Simulation Runner <a class="header-anchor" href="#simulation-runner" aria-label="Permalink to “Simulation Runner”">​</a></h1><p>This guide describes how to build a standalone Unity player and launch deterministic batches of simulation runs from Python.</p><h2 id="standalone-build" tabindex="-1">Standalone Build <a class="header-anchor" href="#standalone-build" aria-label="Permalink to “Standalone Build”">​</a></h2><p>While the simulation can be executed interactively in the Unity Editor, a standalone player allows the simulation to be invoked from the command line. <code>build_standalone.py</code> is a helper script included in the <code>Tools</code> directory of the release to generate a standalone build of the simulator for the current operating system.</p><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to “Requirements”">​</a></h3><p>To run <code>build_standalone.py</code>, ensure that you have Python 3 installed on your system and that you have the <code>absl-py</code> library.</p><h3 id="building" tabindex="-1">Building <a class="header-anchor" href="#building" aria-label="Permalink to “Building”">​</a></h3><p>Run the script as follows:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Tools/build_standalone.py</span></span></code></pre></div><p>You can specify three optional flags:</p><ul><li><strong>--unity_path</strong>: Path to the Unity installation. If not provided, defaults to <code>$UNITY_PATH</code>. If <code>$UNITY_PATH</code> is not provided, the script will automatically search through a list of common directories for a Unity installation.</li><li><strong>--build_name</strong>: Build name. If not provided, defaults to <code>micromissiles</code>.</li><li><strong>--build_root</strong>: Build root directory. If not provided, defaults to <code>Build/</code>.</li></ul><p>The standalone build is stored in a timestamped subdirectory of the build root directory.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># Example build directory on a Mac.</span></span>
<span class="line"><span>Build/</span></span>
<span class="line"><span>  ├── 20251117_104914/</span></span>
<span class="line"><span>  │   ├── micromissiles.app</span></span>
<span class="line"><span>  │   ├── micromissiles_BurstDebugInformation_DoNotShip/</span></span>
<span class="line"><span>  │   └── unity.log</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  └── ...</span></span></code></pre></div><h2 id="run-configuration" tabindex="-1">Run Configuration <a class="header-anchor" href="#run-configuration" aria-label="Permalink to “Run Configuration”">​</a></h2><p>Run configurations are consumed by <code>Tools/run_batch.py</code>, which launches one standalone Unity process per simulation run. Batch runs are only supported on the standalone player and not in the interactive mode in the Unity Editor.</p><h3 id="requirements-1" tabindex="-1">Requirements <a class="header-anchor" href="#requirements-1" aria-label="Permalink to “Requirements”">​</a></h3><p>To run <code>Tools/run_batch.py</code>, ensure that you have Python 3 installed and that the <code>protobuf</code> Python package is available in that environment.</p><p>The run configuration defines the simulation configuration to use, the number of runs to perform, the seed to use for the random number generator, and the maximum number of concurrent worker processes. The <a href="https://github.com/PisterLab/micromissiles-unity/blob/master/Assets/Proto/Configs/run_config.proto" target="_blank" rel="noreferrer"><code>run_config.proto</code></a> file defines the run config proto message used by the batch run launcher. The main benefit of a run configuration is that repeated runs of a single simulation configuration can be scheduled deterministically and aggregated afterwards.</p><p>The run configuration includes:</p><ul><li><strong>name</strong>: Run configuration name used to name the log directory.</li><li><strong>simulation_config_file</strong>: Simulation configuration to use for this run.</li><li><strong>num_runs</strong>: Number of times to run the simulation configuration.</li><li><strong>seed</strong>: Random number generator seed.</li><li><strong>seed_stride</strong>: The seed increment for subsequent runs.</li><li><strong>max_parallel</strong>: Maximum number of Unity worker processes to run concurrently. If omitted or set to <code>0</code>, the launcher runs one worker at a time.</li></ul><h2 id="running-from-command-line" tabindex="-1">Running from Command Line <a class="header-anchor" href="#running-from-command-line" aria-label="Permalink to “Running from Command Line”">​</a></h2><h4 id="flags" tabindex="-1">Flags <a class="header-anchor" href="#flags" aria-label="Permalink to “Flags”">​</a></h4><ul><li><strong><code>--binary_path &lt;path&gt;</code></strong>: Path to the standalone Unity executable.</li><li><strong><code>--run_config &lt;config_file&gt;</code></strong>: Path to the run configuration file, or its filename relative to <code>Assets/StreamingAssets/Configs/Runs</code>.</li><li><strong><code>--log_root_dir &lt;directory&gt;</code></strong> (optional): Root directory in which to create the batch output directory. Defaults to the Unity persistent data path.</li><li><strong><code>--unity-log-dir &lt;directory&gt;</code></strong> (optional): Directory in which to store the per-run Unity logs.</li></ul><h4 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to “Windows”">​</a></h4><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cd .\\Build\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">timestamp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python3 Tools</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">run_batch.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">\`</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">unity_path .\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">micromissiles.exe</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> \`</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">run_config batch_7_quadcopters.pbtxt</span></span></code></pre></div><h4 id="mac" tabindex="-1">Mac <a class="header-anchor" href="#mac" aria-label="Permalink to “Mac”">​</a></h4><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Build/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">timestam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../../Tools/run_batch.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --unity_path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./micromissiles.app</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --run_config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> batch_7_quadcopters.pbtxt</span></span></code></pre></div><h4 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to “Linux”">​</a></h4><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Build/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">timestam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../../Tools/run_batch.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --unity_path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./micromissiles</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --run_config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> batch_7_quadcopters.pbtxt</span></span></code></pre></div><p>Logs are exported to the <code>Logs</code> directory in your operating system&#39;s <a href="https://docs.unity3d.com/ScriptReference/Application-persistentDataPath.html" target="_blank" rel="noreferrer">persistent data path</a>. The batch run launcher creates a parent directory called <code>&lt;run_config_name&gt;_&lt;timestamp&gt;</code>, in which the per-run logs are stored in separate subdirectories called <code>run_&lt;run_index&gt;_seed_&lt;seed&gt;</code>.</p><h2 id="single-run-cli" tabindex="-1">Single-Run CLI <a class="header-anchor" href="#single-run-cli" aria-label="Permalink to “Single-Run CLI”">​</a></h2><p>The standalone Unity player now supports a single-run mode instead of Unity-side batch orchestration. This is the interface used by <code>Tools/run_batch.py</code> for each worker process.</p><ul><li><code>--simulation_config &lt;file&gt;</code>: Simulation configuration filename from <code>Assets/StreamingAssets/Configs/Simulations</code>.</li><li><code>--seed &lt;int&gt;</code>: Explicit deterministic seed for the run.</li><li><code>--output_dir &lt;directory&gt;</code>: Absolute directory in which to store the run&#39;s telemetry and event logs.</li></ul><p>For more details on logging and log processing, consult the <a href="./Simulation_Logging.html">Simulation Logging</a> guide.</p>`,34)])])}const g=s(t,[["render",l]]);export{u as __pageData,g as default};
